// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import {Script, console2} from "forge-std/Script.sol";
import {MainVoting} from "../src/vote/MainVoting.sol";

/// @notice Loads pre-generated vote/signature payload from JSON and submits it on-chain.
/// @dev JSON 구조: UserVoteBatch[] 형식
/// [
///   {
///     "userVoteNo": 227186710,
///     "records": [{ "timestamp": ..., "missionId": ..., ... }],
///     "userBatchSig": { "user": "0x...", "userNonce": 4, "signature": "0x..." }
///   },
///   ...
/// ]
contract SubmitStressVoting is Script {
    MainVoting internal VOTING;

    function run() external {
        VOTING = MainVoting(_envOrAddress("VOTING_ADDRESS", 0x10Fb9C7BFec7d2059b65c9e70B4F58E2E6fd0eFE));
        uint256 executorKey = vm.envUint("PRIVATE_KEY");
        string memory filePath = _envOrString("STRESS_FILE", "stress-artifacts/stress-output.json");
        string memory json = vm.readFile(filePath);

        // UserVoteBatch[] 구조로 파싱
        MainVoting.UserVoteBatch[] memory batches =
            abi.decode(vm.parseJsonBytes(json, ".batches"), (MainVoting.UserVoteBatch[]));

        bytes memory executorSig = vm.parseJsonBytes(json, ".executorSig");
        uint256 batchNonce = vm.parseJsonUint(json, ".batchNonce");

        vm.startBroadcast(executorKey);
        VOTING.submitMultiUserBatch(batches, batchNonce, executorSig);
        vm.stopBroadcast();

        console2.log("Stress payload submitted from", filePath);
    }

    function _envOrString(string memory key, string memory defaultValue) internal returns (string memory) {
        if (vm.envExists(key)) return vm.envString(key);
        return defaultValue;
    }

    function _envOrAddress(string memory key, address defaultValue) internal returns (address) {
        if (vm.envExists(key)) return vm.envAddress(key);
        return defaultValue;
    }
}

src/nft/CelebusNFT.sol.content:
// SPDX-License-Identifier: MIT
// Compatible with OpenZeppelin Contracts ^5.5.0
pragma solidity ^0.8.27;

import {ERC721} from "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import {
    ERC721Burnable
} from "@openzeppelin/contracts/token/ERC721/extensions/ERC721Burnable.sol";
import {
    ERC721Pausable
} from "@openzeppelin/contracts/token/ERC721/extensions/ERC721Pausable.sol";
import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title CelebusNFT
 * @dev Celebus 플랫폼 NFT 컨트랙트
 *
 * 주요 기능:
 * - ERC721 표준 NFT 구현
 * - 일시정지 기능 (pause 시 민팅/전송/소각 모두 차단)
 * - 토큰 잠금 기능 (개별 토큰 전송 차단, 단 Owner는 전송/소각 가능)
 * - 배치 민팅 (가스 효율적인 대량 발행)
 * - Owner만 소각 가능 (사용자는 자신의 NFT도 소각 불가)
 *
 * 보안/권한 특징:
 * - Owner만 민팅, 잠금, 일시정지, 소각 가능
 * - 잠긴 토큰은 Owner만 전송/소각 가능
 * - 중앙집중형 권한 모델(Owner 키에 강하게 의존)
 */
contract CelebusNFT is ERC721, ERC721Pausable, Ownable, ERC721Burnable {
    // ============================================
    // 상태 변수
    // ============================================
    /// @dev 최대 배치 크기
    uint256 public constant MAX_BATCH_SIZE = 1500;
    /// @dev 다음 발행될 토큰 ID (auto increment)
    uint256 private _nextTokenId;

    /// @dev 토큰 메타데이터 Base URI
    string private _baseTokenURI;

    /// @dev 토큰별 잠금 상태 (true = 잠김, false = 잠금 해제)
    mapping(uint256 => bool) private _locked;

    // ============================================
    // 이벤트
    // ============================================

    /// @dev 배치 민팅이 완료되었을 때 발생
    event BatchMinted(
        address indexed to,
        uint256 indexed startTokenId,
        uint256 count
    );

    /// @dev 토큰이 잠겼을 때 발생
    event TokenLocked(uint256 indexed tokenId);

    /// @dev 토큰 잠금이 해제되었을 때 발생
    event TokenUnlocked(uint256 indexed tokenId);

    /// @dev 배치 크기가 최대 크기를 초과할 때 발생
    error BatchSizeExceeded(uint256 requested, uint256 max);

    // ============================================
    // 에러
    // ============================================

    /// @dev 잠긴 토큰을 전송하려 할 때 발생
    error TokenIsLocked(uint256 tokenId);

    /// @dev 존재하지 않는 토큰에 대한 작업 시도 시 발생
    error TokenDoesNotExist(uint256 tokenId);

    /// @dev Owner가 아닌 주소가 소각을 시도할 때 발생
    error OnlyOwnerCanBurn();

    /// @dev 배치 작업 시 빈 배열 또는 0 개수가 전달되었을 때 발생
    error EmptyBatch();

    // ============================================
    // 생성자
    // ============================================

    /**
     * @dev 컨트랙트 초기화
     * @param initialOwner 초기 소유자 주소 (민팅, 잠금, 일시정지 권한)
     */
    constructor(
        address initialOwner
    ) ERC721("CelebusNFT", "CELEB") Ownable(initialOwner) {}

    // ============================================
    // 일시정지 기능
    // ============================================

    /**
     * @dev 모든 NFT 민팅/전송/소각을 일시정지 (긴급 상황용)
     * @notice Owner만 호출 가능
     */
    function pause() public onlyOwner {
        _pause();
    }

    /**
     * @dev 일시정지 해제
     * @notice Owner만 호출 가능
     */
    function unpause() public onlyOwner {
        _unpause();
    }

    // ============================================
    // 민팅 기능
    // ============================================

    /**
     * @dev 단일 NFT 안전 민팅 (auto increment)
     * @param to 받을 주소
     * @return tokenId 발행된 토큰 ID
     * @notice Owner만 호출 가능
     * @notice 토큰 ID는 0부터 자동 증가
     */
    function safeMint(address to) public onlyOwner returns (uint256) {
        uint256 tokenId = _nextTokenId++;
        _safeMint(to, tokenId);
        return tokenId;
    }

    /**
     * @dev 배치 민팅 (auto increment)
     * @param to 받을 주소
     * @param count 민팅할 개수
     * @return startTokenId 시작 토큰 ID
     * @notice Owner만 호출 가능
     * @notice 가스 효율을 위해 루프로 구현
     * @notice 토큰 ID는 현재 _nextTokenId부터 자동 증가
     */
    function batchMint(
        address to,
        uint256 count
    ) external onlyOwner returns (uint256 startTokenId) {
        if (count == 0) revert EmptyBatch();

        if (count > MAX_BATCH_SIZE)
            revert BatchSizeExceeded(count, MAX_BATCH_SIZE);

        startTokenId = _nextTokenId;

        for (uint256 i = 0; i < count; i++) {
            _safeMint(to, _nextTokenId++);
        }

        emit BatchMinted(to, startTokenId, count);
    }

    // ============================================
    // 메타데이터 관리
    // ============================================

    /**
     * @dev Base URI 설정
     * @param baseURI 새로운 Base URI
     * @notice Owner만 호출 가능
     * @notice 모든 토큰의 tokenURI는 baseURI + tokenId 형태
     */
    function setBaseURI(string memory baseURI) external onlyOwner {
        _baseTokenURI = baseURI;
    }

    /**
     * @dev Base URI 반환 (내부 함수)
     * @return 현재 설정된 Base URI
     */
    function _baseURI() internal view override returns (string memory) {
        return _baseTokenURI;
    }

    // ============================================
    // 토큰 잠금 기능
    // ============================================

    /**
     * @dev 토큰 잠금 (전송 차단)
     * @param tokenId 잠글 토큰 ID
     * @notice Owner만 호출 가능
     * @notice 잠긴 토큰은 Owner만 전송/소각 가능
     */
    function lockToken(uint256 tokenId) external onlyOwner {
        if (_ownerOf(tokenId) == address(0)) revert TokenDoesNotExist(tokenId);
        _locked[tokenId] = true;
        emit TokenLocked(tokenId);
    }

    /**
     * @dev 토큰 잠금 해제
     * @param tokenId 잠금 해제할 토큰 ID
     * @notice Owner만 호출 가능
     */
    function unlockToken(uint256 tokenId) external onlyOwner {
        if (_ownerOf(tokenId) == address(0)) revert TokenDoesNotExist(tokenId);
        _locked[tokenId] = false;
        emit TokenUnlocked(tokenId);
    }

    /**
     * @dev 여러 토큰을 배치로 잠금
     * @param tokenIds 잠글 토큰 ID 배열
     * @notice Owner만 호출 가능
     * @notice 배치 크기가 최대 크기를 초과할 때 발생
     */
    function batchLockTokens(uint256[] calldata tokenIds) external onlyOwner {
        if (tokenIds.length == 0) revert EmptyBatch();
        if (tokenIds.length > MAX_BATCH_SIZE)
            revert BatchSizeExceeded(tokenIds.length, MAX_BATCH_SIZE);

        for (uint256 i = 0; i < tokenIds.length; i++) {
            uint256 tokenId = tokenIds[i];
            if (_ownerOf(tokenId) == address(0)) {
                revert TokenDoesNotExist(tokenId);
            }
            _locked[tokenId] = true;
            emit TokenLocked(tokenId);
        }
    }

    /**
     * @dev 여러 토큰의 잠금을 배치로 해제
     * @param tokenIds 잠금 해제할 토큰 ID 배열
     * @notice Owner만 호출 가능
     * @notice 배치 크기가 최대 크기를 초과할 때 발생
     */
    function batchUnlockTokens(uint256[] calldata tokenIds) external onlyOwner {
        if (tokenIds.length == 0) revert EmptyBatch();
        if (tokenIds.length > MAX_BATCH_SIZE)
            revert BatchSizeExceeded(tokenIds.length, MAX_BATCH_SIZE);

        for (uint256 i = 0; i < tokenIds.length; i++) {
            uint256 tokenId = tokenIds[i];
            if (_ownerOf(tokenId) == address(0)) {
                revert TokenDoesNotExist(tokenId);
            }
            _locked[tokenId] = false;
            emit TokenUnlocked(tokenId);
        }
    }

    // ============================================
    // 조회 기능
    // ============================================

    /**
     * @dev 토큰 잠금 상태 확인
     * @param tokenId 확인할 토큰 ID
     * @return 잠김(true) 또는 잠금 해제(false)
     * @notice 존재하지 않는 토큰에 대해서는 TokenDoesNotExist 에러 발생
     */
    function isLocked(uint256 tokenId) public view returns (bool) {
        if (_ownerOf(tokenId) == address(0)) {
            revert TokenDoesNotExist(tokenId);
        }
        return _locked[tokenId];
    }

    // ============================================
    // 소각 기능
    // ============================================

    /**
     * @dev 토큰 소각 (Owner만 가능)
     * @param tokenId 소각할 토큰 ID
     * @notice Owner만 호출 가능
     * @notice 사용자는 자신의 NFT도 소각할 수 없음 (Owner 권한 필요)
     */
    function burn(uint256 tokenId) public override {
        if (msg.sender != owner()) revert OnlyOwnerCanBurn();
        _burn(tokenId);
    }

    // ============================================
    // 내부 함수 오버라이드
    // ============================================

    /**
     * @dev ERC721 전송 로직 오버라이드
     * @param to 받을 주소
     * @param tokenId 토큰 ID
     * @param auth 권한 주소 (Owner면 잠금 무시)
     * @return 이전 소유자 주소
     *
     * 전송/잠금 규칙:
     * - paused() == true: 민팅/전송/소각 모두 차단 (ERC721Pausable 기본 동작)
     * - 잠긴 토큰 전송:
     *   - from != 0, to != 0, _locked[tokenId] == true 인 경우
     *   - auth != owner() 이면 TokenIsLocked 에러로 revert
     *   - Owner는 잠금 상태여도 전송 가능
     * - 소각 시 잠금 플래그 정리 (to == address(0))
     */
    function _update(
        address to,
        uint256 tokenId,
        address auth
    ) internal override(ERC721, ERC721Pausable) returns (address) {
        address from = _ownerOf(tokenId);

        // 민팅(from == address(0)) 또는 소각(to == address(0))이 아닌
        // 일반 전송에서만 잠금 상태를 검사
        if (
            from != address(0) &&
            to != address(0) &&
            _locked[tokenId] &&
            auth != owner()
        ) {
            revert TokenIsLocked(tokenId);
        }

        // 소각 시 잠금 플래그 초기화 (상태 일관성 유지)
        if (to == address(0) && _locked[tokenId]) {
            delete _locked[tokenId];
        }

        return super._update(to, tokenId, auth);
    }
}

